glx(){return"\u0417 \u043c\u0456\u0440\u043a\u0443\u0432\u0430\u043d\u044c \u0431\u0435\u0437\u043f\u0435\u043a\u0438 \u0432\u0438 \u043d\u0435 \u043c\u043e\u0436\u0435\u0442\u0435 \u0432\u0438\u043c\u043a\u043d\u0443\u0442\u0438 \u0448\u0438\u0444\u0440\u0443\u0432\u0430\u043d\u043d\u044f \u0432 \u0431\u0435\u0441\u0456\u0434\u0456, \u0443\u0432 \u044f\u043a\u0456\u0439 \u0432\u043e\u043d\u043e \u0431\u0443\u043b\u043e \u0432\u0432\u0456\u043c\u043a\u043d\u0435\u043d\u0435 \u0440\u0430\u043d\u0456\u0448\u0435."},
